import sys

class Solution:
    def largestBSTSubtree(self, values: list[int], left: list[int], right: list[int]) -> int:
        sys.setrecursionlimit(200000)
        n = len(values) - 1  # values[0] unused, nodes are 1-indexed
        # post-order DFS returning (is_bst, size, min_val, max_val)
        def dfs(u: int):
            if u == -1:
                return (True, 0, float('inf'), float('-inf'))
            l_is, l_sz, l_min, l_max = dfs(left[u])
            r_is, r_sz, r_min, r_max = dfs(right[u])
            cur_val = values[u]
            # check BST property
            if l_is and r_is and l_max < cur_val < r_min:
                sz = l_sz + r_sz + 1
                mn = min(l_min, cur_val)
                mx = max(r_max, cur_val)
                return (True, sz, mn, mx)
            else:
                # not a BST, return the largest size found in children
                return (False, max(l_sz, r_sz), 0, 0)
        _, ans, _, _ = dfs(1)
        return ans

if __name__ == '__main__':
