#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int largestBSTSubtree(vector<int>& values, vector<int>& left, vector<int>& right) {
        int n = values.size() - 1; // values[0] unused, nodes are 1-indexed
        // returns tuple: isBST, size, min, max
        struct Info {bool isBST; int size; long long mn; long long mx;};
        function<Info(int)> dfs = [&](int u) -> Info {
            if (u == -1) return {true, 0, LLONG_MAX, LLONG_MIN};
            Info L = dfs(left[u]);
            Info R = dfs(right[u]);
            long long cur = values[u];
            if (L.isBST && R.isBST && L.mx < cur && cur < R.mn) {
                int sz = L.size + R.size + 1;
                long long mn = min(L.mn, cur);
                long long mx = max(R.mx, cur);
                return {true, sz, mn, mx};
            } else {
                return {false, max(L.size, R.size), 0, 0};
            }
        };
        Info res = dfs(1);
        return res.size;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    if (!(cin >> N)) return 0;
    vector<int> values(N + 1);
    vector<int> left(N + 1);
    vector<int> right(N + 1);
    for (int i = 1; i <= N; ++i) {
        cin >> values[i] >> left[i] >> right[i];
    }
    Solution sol;
    cout << sol.largestBSTSubtree(values, left, right) << "\n";
    return 0;
}
